UPDATE words SET example_en_2 = 'The government plans to increase the minimum wage next year.', example_ko_2 = '정부는 내년에 최저 임금을 인상할 계획이에요.', example_en_3 = 'She earns an hourly wage working at the bakery.', example_ko_3 = '그녀는 제과점에서 시간당 임금을 받고 일해요.', example_en_4 = 'Many workers in that industry receive low wages.', example_ko_4 = '그 업계의 많은 근로자들은 낮은 임금을 받아요.', example_en_5 = 'Higher wages mean people have more money to spend.', example_ko_5 = '더 높은 임금은 사람들이 더 많이 쓸 돈이 있다는 것을 의미해요.' WHERE id = 'w_economy_A2_21';

