UPDATE words SET example_en_2 = 'Macroeconomics examines how government spending affects overall employment.', example_ko_2 = '거시경제학은 정부 지출이 전반적인 고용에 어떤 영향을 미치는지 살펴봐요.', example_en_3 = 'A strong understanding of macroeconomics is essential for policymakers.', example_ko_3 = '거시경제학에 대한 깊은 이해는 정책 입안자들에게 필수적이에요.', example_en_4 = 'Macroeconomics and microeconomics complement each other in understanding the economy.', example_ko_4 = '거시경제학과 미시경제학은 경제를 이해하는 데 서로 보완적이에요.', example_en_5 = 'Her doctoral thesis focused on open-economy macroeconomics.', example_ko_5 = '그녀의 박사 논문은 개방 경제 거시경제학에 초점을 맞췄어요.' WHERE id = 'w_economy_C1_01';

UPDATE words SET example_en_2 = 'Microeconomics helps explain why certain products are priced differently.', example_ko_2 = '미시경제학은 특정 제품의 가격이 왜 다른지 설명하는 데 도움이 돼요.', example_en_3 = 'The course covered both microeconomics and macroeconomics fundamentals.', example_ko_3 = '그 과정은 미시경제학과 거시경제학의 기초를 모두 다뤘어요.', example_en_4 = 'Microeconomics analyzes how firms decide what to produce and at what price.', example_ko_4 = '미시경제학은 기업들이 무엇을 어떤 가격에 생산할지 결정하는 방법을 분석해요.', example_en_5 = 'Using microeconomics, she explained the pricing strategy of the airline industry.', example_ko_5 = '미시경제학을 사용하여 항공 업계의 가격 전략을 설명했어요.' WHERE id = 'w_economy_C1_02';

UPDATE words SET example_en_2 = 'The combination of stagflation and rising debt created a policy nightmare.', example_ko_2 = '스태그플레이션과 부채 상승의 조합이 정책적 악몽을 만들었어요.', example_en_3 = 'She wrote her thesis on the causes and consequences of stagflation.', example_ko_3 = '그녀는 스태그플레이션의 원인과 결과에 대한 논문을 썼어요.', example_en_4 = 'Supply-side shocks can cause stagflation by raising costs and reducing output.', example_ko_4 = '공급 측 충격은 비용을 높이고 생산량을 줄임으로써 스태그플레이션을 유발할 수 있어요.', example_en_5 = 'The fear of stagflation influenced monetary policy decisions significantly.', example_ko_5 = '스태그플레이션에 대한 두려움이 통화 정책 결정에 크게 영향을 미쳤어요.' WHERE id = 'w_economy_C1_03';

UPDATE words SET example_en_2 = 'Traders engaged in arbitrage across different commodity markets.', example_ko_2 = '트레이더들은 다양한 상품 시장에서 차익거래를 했어요.', example_en_3 = 'Arbitrage opportunities disappear quickly in efficient markets.', example_ko_3 = '차익거래 기회는 효율적인 시장에서 빠르게 사라져요.', example_en_4 = 'The hedge fund specialized in statistical arbitrage strategies.', example_ko_4 = '그 헤지펀드는 통계적 차익거래 전략을 전문으로 했어요.', example_en_5 = 'Cryptocurrency arbitrage involves exploiting price differences across exchanges.', example_ko_5 = '암호화폐 차익거래는 거래소 간의 가격 차이를 이용하는 것을 포함해요.' WHERE id = 'w_economy_C1_04';

UPDATE words SET example_en_2 = 'The austerity program failed to restore investor confidence in the country.', example_ko_2 = '긴축 프로그램은 그 나라에 대한 투자자 신뢰를 회복시키는 데 실패했어요.', example_en_3 = 'The opposition strongly criticized the government''s austerity agenda.', example_ko_3 = '야당은 정부의 긴축 의제를 강하게 비판했어요.', example_en_4 = 'Living standards fell sharply under the austerity regime.', example_ko_4 = '긴축 체제 하에서 생활 수준이 급격히 하락했어요.', example_en_5 = 'The social costs of austerity took years to reverse.', example_ko_5 = '긴축의 사회적 비용을 회복하는 데 수년이 걸렸어요.' WHERE id = 'w_economy_C1_05';

UPDATE words SET example_en_2 = 'Deregulation of the electricity market led to lower prices for consumers.', example_ko_2 = '전력 시장 규제 완화가 소비자들의 가격을 낮췄어요.', example_en_3 = 'Critics argue that financial deregulation contributed to the 2008 crisis.', example_ko_3 = '비평가들은 금융 규제 완화가 2008년 위기에 기여했다고 주장해요.', example_en_4 = 'Deregulation can boost competition but may also increase systemic risk.', example_ko_4 = '규제 완화는 경쟁을 강화할 수 있지만 시스템 위험도 증가시킬 수 있어요.', example_en_5 = 'The airline industry was transformed by deregulation in the 1980s.', example_ko_5 = '항공 업계는 1980년대 규제 완화로 변화됐어요.' WHERE id = 'w_economy_C1_06';

UPDATE words SET example_en_2 = 'The privatization of water services sparked widespread public protests.', example_ko_2 = '수도 서비스의 민영화가 광범위한 공개 시위를 촉발했어요.', example_en_3 = 'Privatization is often controversial because it affects public services.', example_ko_3 = '민영화는 공공 서비스에 영향을 미치기 때문에 종종 논란이 돼요.', example_en_4 = 'After privatization, the company improved its efficiency significantly.', example_ko_4 = '민영화 이후 회사는 효율성을 크게 개선했어요.', example_en_5 = 'The government reversed some privatizations after public pressure.', example_ko_5 = '정부는 공개적인 압박 이후 일부 민영화를 되돌렸어요.' WHERE id = 'w_economy_C1_07';

UPDATE words SET example_en_2 = 'The government introduced subsidies for renewable energy to meet climate goals.', example_ko_2 = '정부는 기후 목표를 달성하기 위해 재생 에너지에 대한 보조금을 도입했어요.', example_en_3 = 'Housing subsidies help low-income families afford decent accommodation.', example_ko_3 = '주택 보조금은 저소득 가정이 괜찮은 주거지를 마련하는 데 도움이 돼요.', example_en_4 = 'Critics argue that fossil fuel subsidies slow the transition to clean energy.', example_ko_4 = '비평가들은 화석 연료 보조금이 청정 에너지로의 전환을 늦춘다고 주장해요.', example_en_5 = 'The subsidy was designed to protect domestic producers from cheap imports.', example_ko_5 = '보조금은 저렴한 수입품으로부터 국내 생산자를 보호하기 위해 설계됐어요.' WHERE id = 'w_economy_C1_08';

UPDATE words SET example_en_2 = 'The country imposed tariffs on imported steel to protect local jobs.', example_ko_2 = '그 나라는 지역 일자리를 보호하기 위해 수입 철강에 관세를 부과했어요.', example_en_3 = 'Retaliatory tariffs led to a tit-for-tat trade war.', example_ko_3 = '보복 관세가 맞대응 무역 전쟁으로 이어졌어요.', example_en_4 = 'Free trade agreements remove tariffs on goods exchanged between member countries.', example_ko_4 = '자유무역협정은 회원국 간 교환 상품의 관세를 없애요.', example_en_5 = 'Rising tariffs increased the cost of imported components for manufacturers.', example_ko_5 = '관세 상승이 제조업체들의 수입 부품 비용을 높였어요.' WHERE id = 'w_economy_C1_09';

UPDATE words SET example_en_2 = 'The cartel fixed prices to avoid competition among its members.', example_ko_2 = '카르텔은 회원 간의 경쟁을 피하기 위해 가격을 고정했어요.', example_en_3 = 'The drug cartel controlled trade routes across the region.', example_ko_3 = '마약 카르텔이 그 지역의 무역 경로를 통제했어요.', example_en_4 = 'Antitrust regulators broke up the cartel after a long investigation.', example_ko_4 = '독점금지 규제 기관들이 오랜 조사 끝에 카르텔을 해체했어요.', example_en_5 = 'The cartel''s price-fixing agreement violated competition law.', example_ko_5 = '카르텔의 가격 담합 협정은 경쟁법을 위반했어요.' WHERE id = 'w_economy_C1_10';

UPDATE words SET example_en_2 = 'The mobile phone market in most countries functions as an oligopoly.', example_ko_2 = '대부분의 나라에서 휴대폰 시장은 과점으로 기능해요.', example_en_3 = 'An oligopoly can lead to price-fixing and reduced consumer choice.', example_ko_3 = '과점은 가격 담합과 소비자 선택 감소로 이어질 수 있어요.', example_en_4 = 'The airline industry is often cited as an example of a natural oligopoly.', example_ko_4 = '항공 업계는 종종 자연 과점의 예로 언급돼요.', example_en_5 = 'Regulators monitor oligopolies closely to prevent anti-competitive behavior.', example_ko_5 = '규제 기관들은 반경쟁적 행동을 막기 위해 과점을 면밀히 모니터링해요.' WHERE id = 'w_economy_C1_11';

UPDATE words SET example_en_2 = 'Traffic congestion is a negative externality of urban car ownership.', example_ko_2 = '교통 혼잡은 도시 자동차 소유의 부정적 외부 효과예요.', example_en_3 = 'Carbon taxes are designed to internalize the externality of greenhouse gas emissions.', example_ko_3 = '탄소세는 온실가스 배출의 외부 효과를 내부화하기 위해 설계됐어요.', example_en_4 = 'Education generates a positive externality by benefiting society as a whole.', example_ko_4 = '교육은 사회 전체에 이익을 줌으로써 긍정적 외부 효과를 발생시켜요.', example_en_5 = 'Economists argue that externalities justify some degree of government intervention.', example_ko_5 = '경제학자들은 외부 효과가 어느 정도의 정부 개입을 정당화한다고 주장해요.' WHERE id = 'w_economy_C1_12';

UPDATE words SET example_en_2 = 'The fiscal stimulus helped lift the economy out of recession.', example_ko_2 = '재정 부양책이 경제를 침체에서 끌어내는 데 도움이 됐어요.', example_en_3 = 'The effectiveness of fiscal stimulus depends on how quickly money is spent.', example_ko_3 = '재정 부양책의 효과는 돈이 얼마나 빨리 쓰이느냐에 달려 있어요.', example_en_4 = 'A large fiscal stimulus was announced to support workers during the pandemic.', example_ko_4 = '팬데믹 중 근로자들을 지원하기 위해 대규모 재정 부양책이 발표됐어요.', example_en_5 = 'Opponents of fiscal stimulus argue it increases government debt unnecessarily.', example_ko_5 = '재정 부양책의 반대론자들은 이것이 불필요하게 정부 부채를 늘린다고 주장해요.' WHERE id = 'w_economy_C1_13';

UPDATE words SET example_en_2 = 'The central bank''s decision to hold rates steady surprised markets.', example_ko_2 = '중앙은행의 금리 동결 결정이 시장을 놀라게 했어요.', example_en_3 = 'A credible central bank can manage inflation expectations effectively.', example_ko_3 = '신뢰할 수 있는 중앙은행은 인플레이션 기대를 효과적으로 관리할 수 있어요.', example_en_4 = 'The central bank published minutes from its latest policy meeting.', example_ko_4 = '중앙은행이 최근 정책 회의 의사록을 공개했어요.', example_en_5 = 'Independence of the central bank is seen as vital for sound monetary policy.', example_ko_5 = '중앙은행의 독립성은 건전한 통화 정책에 필수적인 것으로 여겨져요.' WHERE id = 'w_economy_C1_14';

UPDATE words SET example_en_2 = 'Public sector unions organized strikes in response to the austerity measures.', example_ko_2 = '공공 부문 노조들이 긴축 조치에 대응하여 파업을 조직했어요.', example_en_3 = 'The austerity measures included cuts to education and healthcare budgets.', example_ko_3 = '긴축 조치에는 교육 및 의료 예산 삭감이 포함됐어요.', example_en_4 = 'The government introduced austerity measures to regain access to international credit markets.', example_ko_4 = '정부는 국제 신용 시장에 대한 접근을 회복하기 위해 긴축 조치를 도입했어요.', example_en_5 = 'Alternative economists argue that austerity measures are counterproductive during a recession.', example_ko_5 = '대안 경제학자들은 긴축 조치가 경기 침체 중에 역효과를 낸다고 주장해요.' WHERE id = 'w_economy_C1_15';

UPDATE words SET example_en_2 = 'Labor market structural reforms increased flexibility for employers.', example_ko_2 = '노동 시장 구조 개혁이 고용주들의 유연성을 높였어요.', example_en_3 = 'Structural reforms to the pension system were politically unpopular.', example_ko_3 = '연금 제도에 대한 구조 개혁은 정치적으로 인기가 없었어요.', example_en_4 = 'Without structural reforms, the economy would remain uncompetitive.', example_ko_4 = '구조 개혁 없이는 경제가 경쟁력을 유지할 수 없을 거예요.', example_en_5 = 'The World Bank recommended structural reforms to boost long-term growth.', example_ko_5 = '세계은행이 장기 성장을 위해 구조 개혁을 권고했어요.' WHERE id = 'w_economy_C1_16';

UPDATE words SET example_en_2 = 'The rise of protectionism is a major threat to global free trade.', example_ko_2 = '보호무역주의의 부상은 세계 자유 무역에 주요 위협이에요.', example_en_3 = 'Protectionism can protect jobs in the short term but may harm consumers.', example_ko_3 = '보호무역주의는 단기적으로 일자리를 보호할 수 있지만 소비자에게 해가 될 수 있어요.', example_en_4 = 'Economists generally oppose protectionism as it reduces economic efficiency.', example_ko_4 = '경제학자들은 보호무역주의가 경제 효율성을 낮추기 때문에 일반적으로 반대해요.', example_en_5 = 'Protectionism in the 1930s deepened the Great Depression.', example_ko_5 = '1930년대의 보호무역주의가 대공황을 심화시켰어요.' WHERE id = 'w_economy_C1_17';

UPDATE words SET example_en_2 = 'Deposit insurance creates moral hazard by reducing the incentive to monitor banks.', example_ko_2 = '예금 보험은 은행을 감시하는 인센티브를 줄여 도덕적 해이를 만들어요.', example_en_3 = 'Too-big-to-fail policies create moral hazard for large financial institutions.', example_ko_3 = '대마불사 정책이 대형 금융 기관들에게 도덕적 해이를 만들어요.', example_en_4 = 'Moral hazard arises when protection from consequences leads to riskier behavior.', example_ko_4 = '결과로부터의 보호가 더 위험한 행동으로 이어질 때 도덕적 해이가 발생해요.', example_en_5 = 'Regulators try to design rules that minimize moral hazard in financial markets.', example_ko_5 = '규제 기관들은 금융 시장에서 도덕적 해이를 최소화하는 규칙을 설계하려고 해요.' WHERE id = 'w_economy_C1_18';

UPDATE words SET example_en_2 = 'A country should specialize in goods where it has a comparative advantage.', example_ko_2 = '한 나라는 비교우위가 있는 상품에 특화해야 해요.', example_en_3 = 'Comparative advantage explains why countries with different strengths benefit from trading.', example_ko_3 = '비교우위는 서로 다른 강점을 가진 나라들이 거래에서 이익을 얻는 이유를 설명해요.', example_en_4 = 'Understanding comparative advantage is fundamental to international trade theory.', example_ko_4 = '비교우위를 이해하는 것은 국제 무역 이론의 기본이에요.', example_en_5 = 'His comparative advantage was his ability to communicate across cultures.', example_ko_5 = '그의 비교우위는 문화 간에 소통하는 능력이었어요.' WHERE id = 'w_economy_C1_19';

UPDATE words SET example_en_2 = 'Wage growth must keep pace with inflation to maintain purchasing power.', example_ko_2 = '구매력을 유지하려면 임금 성장이 인플레이션을 따라잡아야 해요.', example_en_3 = 'Declining purchasing power has squeezed household budgets.', example_ko_3 = '구매력 하락이 가계 예산을 압박해왔어요.', example_en_4 = 'Technology has boosted productivity and purchasing power in many countries.', example_ko_4 = '기술이 많은 나라에서 생산성과 구매력을 높였어요.', example_en_5 = 'The strongest indicator of economic wellbeing is real purchasing power per capita.', example_ko_5 = '경제적 웰빙의 가장 강력한 지표는 1인당 실질 구매력이에요.' WHERE id = 'w_economy_C1_20';

UPDATE words SET example_en_2 = 'In a free market, prices signal where resources are needed most.', example_ko_2 = '자유 시장에서 가격은 자원이 가장 필요한 곳을 신호해요.', example_en_3 = 'Some argue a free market cannot solve all social problems.', example_ko_3 = '일부는 자유 시장이 모든 사회 문제를 해결할 수 없다고 주장해요.', example_en_4 = 'A free market economy requires strong institutions and clear property rights.', example_ko_4 = '자유 시장 경제는 강한 제도와 명확한 재산권이 필요해요.', example_en_5 = 'The free market failed to provide healthcare equitably without regulation.', example_ko_5 = '자유 시장은 규제 없이 의료를 공평하게 제공하는 데 실패했어요.' WHERE id = 'w_economy_C1_21';

UPDATE words SET example_en_2 = 'A planned economy struggles to respond quickly to changing consumer demands.', example_ko_2 = '계획 경제는 변화하는 소비자 수요에 빠르게 대응하는 데 어려움을 겪어요.', example_en_3 = 'The Soviet Union''s planned economy collapsed in part due to inefficiency.', example_ko_3 = '소련의 계획 경제는 부분적으로 비효율 때문에 붕괴됐어요.', example_en_4 = 'In a planned economy, the state decides what to produce and in what quantities.', example_ko_4 = '계획 경제에서 국가는 무엇을 얼마나 생산할지 결정해요.', example_en_5 = 'Many formerly planned economies transitioned to market-based systems.', example_ko_5 = '많은 구 계획 경제 국가들이 시장 기반 시스템으로 전환했어요.' WHERE id = 'w_economy_C1_22';

UPDATE words SET example_en_2 = 'Investors worried about the country''s sovereign debt as the deficit grew.', example_ko_2 = '적자가 커지면서 투자자들이 그 나라의 국가 채무를 걱정했어요.', example_en_3 = 'A sovereign debt crisis can threaten the stability of the whole financial system.', example_ko_3 = '국가 채무 위기는 전체 금융 시스템의 안정성을 위협할 수 있어요.', example_en_4 = 'Countries issue sovereign debt in the form of government bonds.', example_ko_4 = '나라들은 정부 채권 형태로 국가 채무를 발행해요.', example_en_5 = 'High sovereign debt levels may limit the government''s ability to respond to crises.', example_ko_5 = '높은 국가 채무 수준은 정부의 위기 대응 능력을 제한할 수 있어요.' WHERE id = 'w_economy_C1_23';

UPDATE words SET example_en_2 = 'The theory of crowding out suggests that public spending can reduce private investment.', example_ko_2 = '구축 효과 이론은 공공 지출이 민간 투자를 줄일 수 있다고 제안해요.', example_en_3 = 'High government borrowing leads to crowding out in credit markets.', example_ko_3 = '높은 정부 차입이 신용 시장에서 구축 효과로 이어져요.', example_en_4 = 'Critics of fiscal stimulus cite the risk of crowding out as a major concern.', example_ko_4 = '재정 부양책의 비판론자들은 구축 효과의 위험을 주요 우려사항으로 언급해요.', example_en_5 = 'In a depressed economy, crowding out is less likely to occur.', example_ko_5 = '침체된 경제에서는 구축 효과가 발생할 가능성이 낮아요.' WHERE id = 'w_economy_C1_24';

UPDATE words SET example_en_2 = 'Water supply networks are considered natural monopolies due to high infrastructure costs.', example_ko_2 = '수도 공급망은 높은 인프라 비용 때문에 자연독점으로 여겨져요.', example_en_3 = 'Governments often regulate natural monopolies to protect consumers.', example_ko_3 = '정부는 종종 소비자를 보호하기 위해 자연독점을 규제해요.', example_en_4 = 'A natural monopoly arises when one firm can supply the entire market at a lower cost.', example_ko_4 = '자연독점은 한 기업이 더 낮은 비용으로 전체 시장을 공급할 수 있을 때 발생해요.', example_en_5 = 'Railway networks are a classic example of a natural monopoly.', example_ko_5 = '철도 네트워크는 자연독점의 전형적인 예예요.' WHERE id = 'w_economy_C1_25';

UPDATE words SET example_en_2 = 'Necessities like bread and salt have low price elasticity of demand.', example_ko_2 = '빵과 소금 같은 생필품은 수요의 가격 탄력성이 낮아요.', example_en_3 = 'Luxury goods typically have high price elasticity.', example_ko_3 = '사치품은 일반적으로 가격 탄력성이 높아요.', example_en_4 = 'Understanding price elasticity helps businesses set optimal prices.', example_ko_4 = '가격 탄력성을 이해하면 기업들이 최적 가격을 설정하는 데 도움이 돼요.', example_en_5 = 'The government studied price elasticity before deciding the fuel tax rate.', example_ko_5 = '정부는 연료세율을 결정하기 전에 가격 탄력성을 연구했어요.' WHERE id = 'w_economy_C1_26';

UPDATE words SET example_en_2 = 'Climate change is increasingly viewed as a case of global market failure.', example_ko_2 = '기후 변화는 점점 전 세계적인 시장 실패의 사례로 여겨지고 있어요.', example_en_3 = 'Regulations are justified when market failure leads to poor outcomes.', example_ko_3 = '시장 실패가 나쁜 결과로 이어질 때 규제가 정당화돼요.', example_en_4 = 'Market failure occurs when goods are under- or over-produced by the private sector.', example_ko_4 = '시장 실패는 민간 부문이 상품을 과소 또는 과잉 생산할 때 발생해요.', example_en_5 = 'Healthcare is often cited as an area prone to market failure.', example_ko_5 = '의료는 시장 실패에 취약한 분야로 종종 언급돼요.' WHERE id = 'w_economy_C1_27';

UPDATE words SET example_en_2 = 'A strong balance of payments position gives a country financial stability.', example_ko_2 = '강한 국제수지 지위는 나라에 금융 안정성을 줘요.', example_en_3 = 'The balance of payments includes both the current account and capital account.', example_ko_3 = '국제수지에는 경상계정과 자본계정이 모두 포함돼요.', example_en_4 = 'A persistent deficit in the balance of payments can weaken a currency.', example_ko_4 = '국제수지의 지속적인 적자는 통화를 약화시킬 수 있어요.', example_en_5 = 'The central bank intervened in the currency market to support the balance of payments.', example_ko_5 = '중앙은행이 국제수지를 지원하기 위해 외환 시장에 개입했어요.' WHERE id = 'w_economy_C1_28';

UPDATE words SET example_en_2 = 'During the financial panic, the central bank stepped in as lender of last resort.', example_ko_2 = '금융 공황 중에 중앙은행이 최종 대부자로 개입했어요.', example_en_3 = 'The role of lender of last resort is to prevent bank runs from spiraling out of control.', example_ko_3 = '최종 대부자의 역할은 뱅크런이 통제 불능으로 나선형으로 치닫는 것을 막는 것이에요.', example_en_4 = 'The IMF sometimes acts as a lender of last resort for struggling countries.', example_ko_4 = 'IMF는 때로 어려움을 겪는 나라들의 최종 대부자 역할을 해요.', example_en_5 = 'Without a lender of last resort, isolated bank failures can trigger a systemic crisis.', example_ko_5 = '최종 대부자가 없으면 개별 은행 실패가 시스템 위기를 촉발할 수 있어요.' WHERE id = 'w_economy_C1_29';

UPDATE words SET example_en_2 = 'The government applied Keynesian economics by increasing public investment.', example_ko_2 = '정부는 공공 투자를 늘려 케인즈 경제학을 적용했어요.', example_en_3 = 'Keynesian economics gained renewed interest after the 2008 financial crisis.', example_ko_3 = '케인즈 경제학은 2008년 금융 위기 이후 새로운 관심을 받게 됐어요.', example_en_4 = 'Critics of Keynesian economics argue it leads to excessive government debt.', example_ko_4 = '케인즈 경제학의 비판론자들은 이것이 과도한 정부 부채로 이어진다고 주장해요.', example_en_5 = 'Keynesian economics proposes that aggregate demand is the key driver of output.', example_ko_5 = '케인즈 경제학은 총수요가 생산의 핵심 동인이라고 제안해요.' WHERE id = 'w_economy_C1_30';

UPDATE words SET example_en_2 = 'Supply-side economics became influential in the United States under Reagan.', example_ko_2 = '공급 중심 경제학은 레이건 시대 미국에서 영향력을 갖게 됐어요.', example_en_3 = 'Critics of supply-side economics argue that tax cuts mostly benefit the wealthy.', example_ko_3 = '공급 중심 경제학의 비판론자들은 세금 감면이 주로 부유층에게 이익이 된다고 주장해요.', example_en_4 = 'Supply-side economics holds that reducing regulations boosts economic output.', example_ko_4 = '공급 중심 경제학은 규제 완화가 경제 생산을 촉진한다고 주장해요.', example_en_5 = 'The debate between supply-side and demand-side economics remains unresolved.', example_ko_5 = '공급 중심과 수요 중심 경제학 사이의 논쟁은 아직 해결되지 않았어요.' WHERE id = 'w_economy_C1_31';

UPDATE words SET example_en_2 = 'The opportunity cost of staying in school is the salary you could have earned.', example_ko_2 = '학교에 남아있는 것의 기회 비용은 벌 수 있었던 급여예요.', example_en_3 = 'Every business decision involves weighing opportunity costs.', example_ko_3 = '모든 사업 결정은 기회 비용을 고려하는 것을 포함해요.', example_en_4 = 'The opportunity cost of buying a house is the return you could have earned investing the money.', example_ko_4 = '집을 사는 기회 비용은 돈을 투자해서 벌 수 있었던 수익이에요.', example_en_5 = 'Time is also a resource with opportunity cost.', example_ko_5 = '시간도 기회 비용이 있는 자원이에요.' WHERE id = 'w_economy_C1_32';

UPDATE words SET example_en_2 = 'Hyperinflation makes it nearly impossible to plan for the future.', example_ko_2 = '초인플레이션은 미래를 계획하는 것을 거의 불가능하게 만들어요.', example_en_3 = 'Germany experienced severe hyperinflation in the early 1920s.', example_ko_3 = '독일은 1920년대 초에 심각한 초인플레이션을 경험했어요.', example_en_4 = 'Hyperinflation destroys the value of savings and undermines trust in the currency.', example_ko_4 = '초인플레이션은 저축의 가치를 파괴하고 통화에 대한 신뢰를 해쳐요.', example_en_5 = 'The government printed money to pay its debts, which led to hyperinflation.', example_ko_5 = '정부가 빚을 갚기 위해 돈을 찍었고, 이것이 초인플레이션으로 이어졌어요.' WHERE id = 'w_economy_C1_33';

UPDATE words SET example_en_2 = 'The finance minister pledged a path to fiscal consolidation over five years.', example_ko_2 = '재정 장관은 5년에 걸친 재정 건전화 경로를 약속했어요.', example_en_3 = 'Fiscal consolidation often involves a mix of spending cuts and tax increases.', example_ko_3 = '재정 건전화는 종종 지출 삭감과 세금 인상의 조합을 포함해요.', example_en_4 = 'The IMF supported the government''s plan for gradual fiscal consolidation.', example_ko_4 = 'IMF는 점진적 재정 건전화를 위한 정부 계획을 지지했어요.', example_en_5 = 'Fiscal consolidation was necessary after years of deficit spending.', example_ko_5 = '수년간의 적자 지출 이후 재정 건전화가 필요했어요.' WHERE id = 'w_economy_C1_34';

UPDATE words SET example_en_2 = 'Income inequality has widened significantly in many developed countries.', example_ko_2 = '많은 선진국에서 소득 불평등이 크게 심화됐어요.', example_en_3 = 'Policies such as progressive taxation can help reduce income inequality.', example_ko_3 = '누진세와 같은 정책이 소득 불평등을 줄이는 데 도움이 될 수 있어요.', example_en_4 = 'Income inequality is linked to differences in education and social mobility.', example_ko_4 = '소득 불평등은 교육과 사회적 이동성의 차이와 연관이 있어요.', example_en_5 = 'High income inequality can undermine social cohesion and trust.', example_ko_5 = '높은 소득 불평등은 사회적 결속력과 신뢰를 약화시킬 수 있어요.' WHERE id = 'w_economy_C1_35';

